@@ -29,0 +29,1 @@
+import jdk.incubator.code.CodeItem;
@@ -79,6 +80,9 @@
-                        for (Value operand : ioh.op().operands()) {
-                            if (!(operand.type() instanceof PrimitiveType) && rootValues.containsKey(operand)) {
